const body = $json.body || $json;

const eventType = body.type || '';
const data = body.data || {};
const payment = data.object?.payment || data.object || data.payment || {};

if (eventType !== 'payment.updated') {
  return [
    {
      json: {
        process: false,
        success: true,
        skipped: true,
        reason: 'Not payment.updated',
        event_type: eventType,
        timestamp: new Date().toISOString()
      }
    }
  ];
}

if (payment.status !== 'COMPLETED') {
  return [
    {
      json: {
        process: false,
        success: true,
        skipped: true,
        reason: 'Payment not completed',
        actual_status: payment.status || 'unknown',
        timestamp: new Date().toISOString()
      }
    }
  ];
}

let orderId = String(payment.reference_id || '').trim();
const squareOrderId = String(payment.order_id || '').trim();

if (!orderId && squareOrderId) {
  orderId = squareOrderId;
}

const totalCents =
  payment.total_money?.amount ||
  payment.amount_money?.amount ||
  0;

return [
  {
    json: {
      trigger_source: 'square',
      order_id: orderId,
      square_order_id: squareOrderId,
      source_type: 'square-webhook',
      triggered_at: new Date().toISOString(),
      payment_id: payment.id || '',
      receipt_url: payment.receipt_url || '',
      total_cents: totalCents,
      skip: false
    }
  }
];

const data = { ...$json };

data.order_id = String(data.order_id || '').trim();

if (data.skip === true) {
  return [
    {
      json: {
        process: false,
        success: true,
        skipped: true,
        reason: data.reason || 'Skipped event',
        event_type: data.event_type || '',
        actual_status: data.actual_status || '',
        timestamp: new Date().toISOString()
      }
    }
  ];
}

if (!data.order_id) {
  return [
    {
      json: {
        process: false,
        success: false,
        skipped: true,
        error: 'Missing order_id',
        reason: 'No order_id/reference_id was found in trigger payload',
        timestamp: new Date().toISOString()
      }
    }
  ];
}

data.process = true;

return [
  {
    json: data
  }
];

const row = Array.isArray($json) ? ($json[0] || {}) : $json;

if (!row || !row.order_id) {
  return [
    {
      json: {
        error: 'NOT_FOUND',
        order_id: 'unknown'
      }
    }
  ];
}

return [
  {
    json: row
  }
];

const sqlite3 = require('sqlite3').verbose();

const dbPath = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';

const orderId = String($json.order_id || '').trim();

return new Promise((resolve) => {
  if (!orderId) {
    resolve([
      {
        json: {
          error: 'NOT_FOUND',
          order_id: '',
          reason: 'Missing order_id before DB lookup'
        }
      }
    ]);
    return;
  }

  const db = new sqlite3.Database(dbPath, (err) => {
    if (err) {
      resolve([
        {
          json: {
            error: 'DB_OPEN_ERROR',
            db_error: err.message,
            order_id: orderId
          }
        }
      ]);
      return;
    }

    db.get(
      `
      SELECT
        order_id,
        email_sent,
        customer_email,
        customer_name,
        cart_json,
        subtotal_cents,
        tax_cents,
        total_cents,
        source,
        NULL AS error
      FROM orders
      WHERE order_id = ?
      LIMIT 1
      `,
      [orderId],
      function(err, row) {
        if (err) {
          resolve([
            {
              json: {
                error: 'DB_QUERY_ERROR',
                db_error: err.message,
                order_id: orderId
              }
            }
          ]);

          db.close();
          return;
        }

        if (!row) {
          resolve([
            {
              json: {
                order_id: orderId,
                email_sent: null,
                customer_email: null,
                customer_name: null,
                cart_json: '[]',
                subtotal_cents: 0,
                tax_cents: 0,
                total_cents: 0,
                source: null,
                error: 'NOT_FOUND'
              }
            }
          ]);

          db.close();
          return;
        }

        resolve([
          {
            json: row
          }
        ]);

        db.close();
      }
    );
  });
});

const dbData = $json;

let cart = [];

try {
  cart = JSON.parse(dbData.cart_json || '[]');

  if (!Array.isArray(cart)) {
    cart = [];
  }
} catch (e) {
  cart = [];
}

const subtotal = ((Number(dbData.subtotal_cents) || 0) / 100).toFixed(2);
const tax = ((Number(dbData.tax_cents) || 0) / 100).toFixed(2);
const total = ((Number(dbData.total_cents) || 0) / 100).toFixed(2);

return [
  {
    json: {
      order_id: dbData.order_id,
      customer_name: dbData.customer_name || 'Valued Customer',
      email: dbData.customer_email || '',
      source: dbData.source || 'unknown',
      cart,
      subtotal,
      tax,
      total
    }
  }
];

const cart = $json.cart || [];

function esc(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

let cartHtml = '<table style="width:100%;border-collapse:collapse;font-size:14px;">';

if (cart.length === 0) {
  cartHtml += '<tr><td colspan="2" style="padding:8px 0;color:#1F1B1D;">No cart items were stored for this order.</td></tr>';
}

cart.forEach(function(item) {
  const qty = Number(item.qty ?? item.quantity ?? 1) || 1;

  let unitPrice = Number(
    item.price ??
    item.unit_price ??
    item.price_dollars ??
    0
  ) || 0;

  if (item.price_cents !== undefined) {
    unitPrice = (Number(item.price_cents) || 0) / 100;
  }

  let lineTotal = unitPrice * qty;

  if (item.line_total_cents !== undefined) {
    lineTotal = (Number(item.line_total_cents) || 0) / 100;
  }

  cartHtml += '<tr>' +
    '<td style="padding:8px 0;color:#1F1B1D;">' +
    qty + 'x ' + esc(item.name || 'Item') +
    '</td>' +
    '<td style="text-align:right;color:#1F1B1D;">$' +
    lineTotal.toFixed(2) +
    '</td>' +
    '</tr>';

  const modifiers = Array.isArray(item.modifiers) ? item.modifiers : [];

  modifiers.forEach(function(mod) {
    const modName =
      typeof mod === 'string'
        ? mod
        : mod.name || mod.label || 'Modifier';

    cartHtml += '<tr>' +
      '<td colspan="2" style="padding:0 0 6px 18px;color:#754681;font-size:12px;">• ' +
      esc(modName) +
      '</td>' +
      '</tr>';
  });
});

cartHtml +=
  '<tr><td colspan="2"><hr style="border:none;border-top:1px solid #E6E1E1;margin:12px 0;" /></td></tr>' +
  '<tr><td style="padding:4px 0;color:#1F1B1D;">Subtotal</td><td style="text-align:right;color:#1F1B1D;">$' + $json.subtotal + '</td></tr>' +
  '<tr><td style="padding:4px 0;color:#1F1B1D;">Tax</td><td style="text-align:right;color:#1F1B1D;">$' + $json.tax + '</td></tr>' +
  '<tr style="font-weight:700;"><td style="padding:8px 0;color:#590B3F;">Total</td><td style="text-align:right;color:#590B3F;">$' + $json.total + '</td></tr>' +
  '</table>';

return [
  {
    json: {
      ...$json,
      CART_HTML: cartHtml
    }
  }
];

const data = $json;
const year = new Date().getFullYear();

function esc(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

let orderType = 'Order';
let subjectLine = 'Your Utopia Deli Order Receipt';
let pickupText = "We're preparing your order now.";

if (data.source === 'meal-prep') {
  orderType = 'Meal Prep Order';
  subjectLine = 'Your Utopia Deli Meal Prep Receipt';
  pickupText = 'Your meals are being prepared fresh for Thursday pickup.';
} else if (data.source === 'pickup-order') {
  orderType = 'Pickup Order';
  subjectLine = 'Your Utopia Deli Pickup Order Receipt';
  pickupText = "We're preparing your pickup order now.";
}

const emailHtml =
  '<div style="font-family:Arial,sans-serif;max-width:600px;margin:auto;background:#FBF6F6;padding:24px;">' +

    '<div style="text-align:center;margin-bottom:24px;">' +
      '<a href="https://www.theutopiadeli.com" target="_blank">' +
        '<img src="https://cdn.shopify.com/s/files/1/0763/5042/3270/files/TheUtopiaDeliLogo_menu.png?v=1774974380" style="max-width:220px;height:auto;" alt="The Utopia Deli" />' +
      '</a>' +
    '</div>' +

    '<p style="color:#590B3F;font-size:24px;font-weight:700;margin:0 0 8px;">Payment received ✅</p>' +

    '<p style="color:#754681;font-style:italic;margin:0 0 18px;">The Utopia Deli. It&apos;s just good food.</p>' +

    '<p style="font-size:14px;color:#1F1B1D;line-height:1.5;">Thanks for your payment, ' +
      esc(data.customer_name) +
      '. ' +
      pickupText +
    '</p>' +

    '<p style="font-size:14px;color:#1F1B1D;margin-top:16px;"><strong>' +
      orderType +
      ' #:</strong> ' +
      esc(data.order_id) +
    '</p>' +

    '<h3 style="color:#590B3F;margin-top:24px;">Order Summary</h3>' +

    (data.CART_HTML || '') +

    '<p style="margin-top:24px;font-size:12px;color:#8A8585;text-align:center;line-height:1.5;">' +
      '&copy; ' + year + '<br/>' +
      'The Utopia Deli<br/>' +
      '801 S Chester St, Little Rock, AR 72202<br/>' +
      '+1 (501) 551-5944' +
    '</p>' +

  '</div>';

return [
  {
    json: {
      ...data,
      email_html: emailHtml,
      email_subject: subjectLine
    }
  }
];

return [
  {
    json: {
      success: true,
      order_id: $node['Build Branded Email'].json.order_id || 'unknown',
      email: $node['Build Branded Email'].json.email || '',
      email_sent: true,
      timestamp: new Date().toISOString()
    }
  }
];

return [
  {
    json: {
      success: true,
      deduplicated: true,
      reason: 'Email already sent for this order',
      order_id: $json.order_id || 'unknown',
      timestamp: new Date().toISOString()
    }
  }
];

return [
  {
    json: {
      success: false,
      error: 'No email address for customer',
      order_id: $json.order_id || 'unknown',
      timestamp: new Date().toISOString()
    }
  }
];

const sqlite3 = require('sqlite3').verbose();

const dbPath = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';

const orderId = String(
  $json.order_id ||
  $node['Build Branded Email'].json.order_id ||
  ''
).trim();

return new Promise((resolve) => {
  if (!orderId) {
    resolve([
      {
        json: {
          email_marked_sent: false,
          error: 'Missing order_id before email_sent update'
        }
      }
    ]);
    return;
  }

  const db = new sqlite3.Database(dbPath, (err) => {
    if (err) {
      resolve([
        {
          json: {
            email_marked_sent: false,
            db_error: err.message,
            order_id: orderId
          }
        }
      ]);
      return;
    }

    db.run(
      `
      UPDATE orders
      SET
        email_sent = 1,
        email_sent_at = datetime('now')
      WHERE order_id = ?
      `,
      [orderId],
      function(err) {
        if (err) {
          resolve([
            {
              json: {
                email_marked_sent: false,
                db_error: err.message,
                order_id: orderId
              }
            }
          ]);

          db.close();
          return;
        }

        resolve([
          {
            json: {
              email_marked_sent: true,
              rows_updated: this.changes,
              order_id: orderId
            }
          }
        ]);

        db.close();
      }
    );
  });
});

return [
  {
    json: {
      success: false,
      error: 'Order not found in database',
      order_id: $json.order_id || 'unknown',
      timestamp: new Date().toISOString()
    }
  }
];

return [
  {
    json: {
      success: $json.success ?? true,
      skipped: true,
      reason: $json.reason || $json.error || 'Skipped event',
      event_type: $json.event_type || '',
      actual_status: $json.actual_status || '',
      timestamp: new Date().toISOString()
    }
  }
];
